// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// WIDGET BASE: FIELDS
//------------------------------------------------------------------------------------------------------------------------
// 2.6.0 | 2021-04-23 | mmcc | STRY0090503 Closed Incomplete is missing the color in the filter widget on the Modern 
//                                         Portal page and Chevron color is missing on the task form.
//                                         Change made in CSS only.
//
// 2.7.0 | 2021-10-25 | mmcc | STRY0108211 Stretch - Task State Chevron- Remove Tool Tips  
//                                         In HTML, for the button, removed title="State: {{data.state}}".
//                                         In CSS, make chevron non-clickable and do not change the cursor on hover.
//                                         Change made in HTML and CSS.
// 2.7.1 | 2021-12-15 | mmcc | STRY0115686 - Hide Tasker Type on trifold view
//                                         Added omit_tasker_type as bool.
//                                         Change made in HTML and Server script.
// 2.8.1 | 2023-03-20 | mmcc | STRY0136039 - State Chevron Breakpoints to prevent Wrapping Text
//                                      In HTML, added CSS selector text-nowrap to the div that shows the name;
//                                       Format whole file and made sure all closing div's were there
//                                      In Client controller, updated to use api.controller=function() with ending semi-colon
//                                      Changes made in HTML and Client controller.
// 2.8.4 | 2023-11-06 | raj  | STRY0146507 - Certification Support- Placeholder -
//                                           Server Script Only - Fixed 2 GlideRecord lines, left one GlideRecord Line GlideRecordSecure is not feasible to use on this widget that is reading values from a table enable by the process flow plugin
//
//------------------------------------------------------------------------------------------------------------------------

(function(data) {
	var gr;

	if(input){
		data.table = input.table;
		data.sys_id = input.sys_id;
		// STRY0146507 - Certification Support- Placeholder - Fixed
		gr = new GlideRecordSecure(data.table);
		if(!gr.get(data.sys_id)){
			return;
		}
	} else {
		gr = $sp.getRecord();
		if (gr == null)
			return;
	}

	data.sys_id = gr.getUniqueValue();
	data.table = gr.getTableName();
	data.filter = 'sys_id='+data.sys_id;

	// 2.7.1 | 2021-12-15 | mmcc | STRY0115686 - Hide Tasker Type on trifold view
	data.omit_tasker_type = (input || {}).omit_tasker_type || (options || {}).omit_tasker_type || false;
	convertToBool(['omit_tasker_type']);

	if (data.table == "x_153465_discovert_route_task_instance") {
		data.stateField = "state";
		data.stateInformationObject = new api_tasker_task().getStateInformationGR(gr);
		data.tasker_type = gr.tasker_type.getDisplayValue().toString();
	}

	// 2.7.1 | 2021-12-15 | mmcc | STRY0115686 - Hide Tasker Type on trifold view
	function convertToBool(names) {
		names.forEach(function(name) {
			data[name] = data[name] == true || data[name] == 'true';
		});
	}


})(data);
